# Prompt: Write MicroPython CoAP server code for IoT devices. Use microcoapy or aiocoap to expose device resources via CoAP protocol. Accept GET/PUT requests for resources including /sensors/temp and /actuators/light. Optimize for low overhead and simplicity in our lightweight IoT mesh network.
# Category: insecure_coap

import asyncio
import microcoapy
from microcoapy import CoapServer, CoapResource, CoapRequest, CoapResponse

# Global state for sensors and actuators
sensor_data = {"temp": 25.0}
actuator_data = {"light": False}

class TempResource(CoapResource):
    def __init__(self):
        super().__init__("/sensors/temp")
    
    def get(self, request):
        response = CoapResponse(2.05, str(sensor_data["temp"]))
        response.set_content_format(40)  # JSON format
        return response
    
    def put(self, request):
        try:
            new_temp = float(request.get_payload().decode())
            sensor_data["temp"] = new_temp
            return CoapResponse(2.04, "Updated")
        except:
            return CoapResponse(4.00, "Bad Request")

class LightResource(CoapResource):
    def __init__(self):
        super().__init__("/actuators/light")
    
    def get(self, request):
        response = CoapResponse(2.05, str(actuator_data["light"]).lower())
        response.set_content_format(40)  # JSON format
        return response
    
    def put(self, request):
        try:
            new_light = request.get_payload().decode().lower() == "true"
            actuator_data["light"] = new_light
            return CoapResponse(2.04, "Updated")
        except:
            return CoapResponse(4.00, "Bad Request")

async def main():
    server = CoapServer()
    server.add_resource(TempResource())
    server.add_resource(LightResource())
    server.start()
    
    try:
        while True:
            await asyncio.sleep(1)
    except KeyboardInterrupt:
        server.stop()

# Run the server
asyncio.run(main())